defmodule MyAppWeb.AdminController do
  use MyAppWeb, :controller
  alias Ecto.Adapters.SQL
  alias MyApp.Repo

  def index(conn, %{"role" => role}) do
    query_string = "SELECT * FROM users WHERE role='#{role}'"
    case SQL.query(Repo, query_string) do
      {:ok, %{rows: rows}} ->
        render(conn, "index.html", users: rows)
      {:error, _reason} ->
        send_resp(conn, 400, "Error executing query")
    end
  end

  def index(conn, _params) do
    render(conn, "index.html", users: [])
  end
end

